import React from 'react';
import { GraduationCap, Briefcase, Building } from 'lucide-react';

const Benefits: React.FC = () => {
  const userBenefits = [
    {
      icon: <GraduationCap className="w-8 h-8" />,
      title: "Law Students",
      description: "Gain practical experience before entering the workforce, building confidence and competence.",
      features: [
        "Practice unlimited realistic legal scenarios",
        "Make mistakes in a safe environment",
        "Receive instant AI-powered feedback",
        "Build practical skills through consequence-based learning"
      ]
    },
    {
      icon: <Briefcase className="w-8 h-8" />,
      title: "Junior Lawyers",
      description: "Accelerate professional development with risk-free practice in challenging legal scenarios.",
      features: [
        "Master courtroom skills without real-world consequences",
        "Create portfolios of their best performances",
        "Compete with peers in multiplayer mode",
        "Receive personalized skill development recommendations"
      ]
    },
    {
      icon: <Building className="w-8 h-8" />,
      title: "Law Firms",
      description: "Enhance training programs and onboarding processes with standardized, scalable simulations.",
      features: [
        "Reduce associate training costs by 70%",
        "Faster time-to-productivity for new associates",
        "Standardized skill development and assessment",
        "Objective performance metrics for talent evaluation"
      ]
    }
  ];

  return (
    <section className="py-16 bg-gray-50">
      <div className="container mx-auto px-4">
        <div className="text-center max-w-3xl mx-auto mb-16">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900 mb-6">
            Who Benefits From CourtCraft
          </h2>
          <p className="text-xl text-gray-600">
            Our platform is designed to meet the needs of law students, junior lawyers, and law firms alike.
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {userBenefits.map((benefit, index) => (
            <div 
              key={index} 
              className="bg-white rounded-2xl shadow-sm hover:shadow-md transition duration-300 overflow-hidden border border-gray-100"
            >
              <div className="bg-gradient-to-r from-indigo-500 to-purple-600 p-6 text-white">
                <div className="flex items-center mb-4">
                  <div className="mr-4">
                    {benefit.icon}
                  </div>
                  <h3 className="text-2xl font-bold">{benefit.title}</h3>
                </div>
                <p className="text-indigo-100">{benefit.description}</p>
              </div>
              <div className="p-6">
                <ul className="space-y-3">
                  {benefit.features.map((feature, featureIndex) => (
                    <li key={featureIndex} className="flex items-start">
                      <div className="w-5 h-5 rounded-full bg-green-100 flex items-center justify-center mt-0.5 mr-3 flex-shrink-0">
                        <div className="w-2 h-2 rounded-full bg-green-500"></div>
                      </div>
                      <span className="text-gray-700">{feature}</span>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Benefits;
